insert into v1_313abb4a2d41932400dfe2ca0bde863f2ce6c6bd90192e0f1bd47d92b70372bb values (11601, 'ツムギのボトルキャップ', 1, 6, 0.625, 0.75, 'ツムギ・オンステージ！ツムギがキャップのステージでかわいく\\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\\n能。');
insert into v1_313abb4a2d41932400dfe2ca0bde863f2ce6c6bd90192e0f1bd47d92b70372bb values (11602, 'ツムギのサマーボトルキャップ', 1, 6, 0.625, 0.75, 'サマー衣装のツムギが、キャップでオンステージ！涼しげな衣装を\\nまとい、熱いステージを繰り広げた彼女の勇姿を思い出すことがで\\nきる。');
insert into v1_313abb4a2d41932400dfe2ca0bde863f2ce6c6bd90192e0f1bd47d92b70372bb values (11603, 'ノゾミのボトルキャップ', 1, 6, 0.625, 0.75, 'ノゾミ・オンステージ！ノゾミがキャップのステージでかわいく\\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\\n能。');
insert into v1_313abb4a2d41932400dfe2ca0bde863f2ce6c6bd90192e0f1bd47d92b70372bb values (11604, 'ノゾミのサマーボトルキャップ', 1, 6, 0.625, 0.75, 'サマー衣装のノゾミが、キャップでオンステージ！涼しげな衣装を\\nまとい、熱いステージを繰り広げた彼女の勇姿を思い出すことがで\\nきる。');
