insert into v1_313abb4a2d41932400dfe2ca0bde863f2ce6c6bd90192e0f1bd47d92b70372bb values (11701, 'ツムギのミニタペストリー', 1, 4, 0.890625, 0.8828125, 'ツムギのキーホルダーサイズのタペストリー。どこにでも飾れる\\nうえに、身につけてお出掛けもできてしまう万能な一品。');
